import torch
import torch.nn as nn
import torch.nn.functional as F


class smaat_depthwise_refine_unet(nn.Module):
    class ReflectionConv2d(nn.Module):
        def __init__(self, in_channels, out_channels, kernel_size=3, bias=False):
            super().__init__()
            pad = kernel_size // 2
            self.pad = nn.ReflectionPad2d(pad) if pad > 0 else nn.Identity()
            self.conv = nn.Conv2d(in_channels, out_channels, kernel_size, padding=0, bias=bias)

        def forward(self, x):
            return self.conv(self.pad(x))

    class DepthwiseSeparableBlock(nn.Module):
        def __init__(self, in_channels, out_channels):
            super().__init__()
            self.proj = nn.Sequential(
                smaat_depthwise_refine_unet.ReflectionConv2d(in_channels, out_channels, kernel_size=1, bias=False),
                nn.BatchNorm2d(out_channels),
                nn.SiLU(inplace=True),
            )
            self.body = nn.Sequential(
                nn.ReflectionPad2d(1),
                nn.Conv2d(out_channels, out_channels, 3, groups=out_channels, padding=0, bias=False),
                nn.BatchNorm2d(out_channels),
                nn.SiLU(inplace=True),
                smaat_depthwise_refine_unet.ReflectionConv2d(out_channels, out_channels, kernel_size=1, bias=False),
                nn.BatchNorm2d(out_channels),
                nn.SiLU(inplace=True),
                nn.ReflectionPad2d(1),
                nn.Conv2d(out_channels, out_channels, 3, groups=out_channels, padding=0, bias=False),
                nn.BatchNorm2d(out_channels),
                nn.SiLU(inplace=True),
                smaat_depthwise_refine_unet.ReflectionConv2d(out_channels, out_channels, kernel_size=1, bias=False),
                nn.BatchNorm2d(out_channels),
            )
            self.act = nn.SiLU(inplace=True)

        def forward(self, x):
            x = self.proj(x)
            return self.act(x + self.body(x))

    class DecoderBlock(nn.Module):
        def __init__(self, in_channels, skip_channels, out_channels):
            super().__init__()
            self.fuse = smaat_depthwise_refine_unet.DepthwiseSeparableBlock(
                in_channels + skip_channels, out_channels
            )

        def forward(self, x, skip):
            x = F.interpolate(x, size=skip.shape[-2:], mode="bilinear", align_corners=False)
            x = torch.cat([x, skip], dim=1)
            return self.fuse(x)

    def __init__(self, in_channels=1, out_channels=1, n_c=16, depth=7):
        super().__init__()
        depth = max(1, int(depth))
        channels = [min(n_c * (2 ** i), n_c * 8) for i in range(depth)]

        self.encoders = nn.ModuleList()
        prev_channels = in_channels
        for ch in channels:
            self.encoders.append(self.DepthwiseSeparableBlock(prev_channels, ch))
            prev_channels = ch

        self.bottleneck = self.DepthwiseSeparableBlock(channels[-1], channels[-1])

        self.decoders = nn.ModuleList()
        for i in range(depth - 2, -1, -1):
            self.decoders.append(self.DecoderBlock(channels[i + 1], channels[i], channels[i]))

        self.refine = nn.Sequential(
            self.DepthwiseSeparableBlock(channels[0], channels[0]),
            self.ReflectionConv2d(channels[0], out_channels, kernel_size=1, bias=True),
        )

    def forward(self, x):
        valid = ~torch.isnan(x)
        x_masked = torch.where(valid, x, torch.zeros_like(x))

        skips = []
        h = x_masked
        for i, encoder in enumerate(self.encoders):
            h = encoder(h)
            skips.append(h)
            if i < len(self.encoders) - 1:
                h = F.avg_pool2d(h, kernel_size=2, stride=2)

        h = self.bottleneck(h)

        for decoder, skip in zip(self.decoders, reversed(skips[:-1])):
            h = decoder(h, skip)

        output = self.refine(h)

        if output.shape[-2:] != x.shape[-2:]:
            output = F.interpolate(output, size=x.shape[-2:], mode="bilinear", align_corners=False)

        if valid.shape[1] == output.shape[1] or valid.shape[1] == 1:
            output_valid = valid
        else:
            output_valid = valid.all(dim=1, keepdim=True)

        output = output.clone()
        output[~output_valid.expand_as(output)] = float("nan")
        return output
